// src/components/tools/SoloGenerator.tsx

import React, { useState, useEffect, useRef } from 'react';
import { useMusic } from '../../context/MusicContext';
import { generateSynchronizedSolo, type SyncSoloData } from '../../services/AIEngine';
import { generateTips, type Tip } from '../../utils/tipsGenerator';
import TablatureDisplay from '../fretboard/TablatureDisplay';
import * as Tone from 'tone';

const ALL_NOTES = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];

const SoloGenerator: React.FC = () => {
  const { 
    keyNote, 
    mode, 
    bpm, 
    timeSignature, 
    getScaleNotes,
    getDiatonicChords,
    setKeyNote,
    setMode,
    setBpm
  } = useMusic();

  const [soloData, setSoloData] = useState<SyncSoloData | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isLoopOn, setIsLoopOn] = useState(false);
  const [isMetronomeOn, setIsMetronomeOn] = useState(false);
  const [isChordsOn, setIsChordsOn] = useState(true);
  const [isSoloOn, setIsSoloOn] = useState(true);
  const [playbackProgress, setPlaybackProgress] = useState(0);
  const [tips, setTips] = useState<Tip[]>([]);
  const [diatonicChords, setDiatonicChords] = useState<any[]>([]);
  const [progression, setProgression] = useState<{ name: string; notes: string[] }[]>([]);
  const [editingBarIndex, setEditingBarIndex] = useState<number | null>(null);

  const chordSynthRef = useRef<Tone.PolySynth | null>(null);
  const soloSynthRef = useRef<Tone.PolySynth | null>(null);
  const samplerRef = useRef<Tone.Sampler | null>(null);
  const metronomeSynthRef = useRef<Tone.MembraneSynth | null>(null); 
  
  const playheadAnimRef = useRef<number>(0);
  const scheduledEventsRef = useRef<any[]>([]);
  const loopIntervalRef = useRef<any>(null);
  const metronomeIntervalRef = useRef<any>(null);

  // Локальный генератор нот аккорда для обхода ограничений типа DiatonicChord
  const getChordNotesLocal = (chordName: string, key: string): string[] => {
    const root = chordName.replace(/[^A-G#b]/g, '');
    const quality = chordName.replace(/[A-G#b]/g, '');
    const map: Record<string, string> = { 'Db': 'C#', 'Eb': 'D#', 'Gb': 'F#', 'Ab': 'G#', 'Bb': 'A#' };
    const normalizedRoot = map[root] || root;
    const rootIdx = ALL_NOTES.indexOf(normalizedRoot);
    if (rootIdx === -1) return [key, ALL_NOTES[(ALL_NOTES.indexOf(key) + 4) % 12], ALL_NOTES[(ALL_NOTES.indexOf(key) + 7) % 12]];

    let intervals: number[] = [0, 4, 7]; // Мажор по умолчанию
    if (quality.includes('m') || quality.includes('min')) intervals = quality.includes('7') ? [0, 3, 7, 10] : [0, 3, 7];
    if (quality === '7') intervals = [0, 4, 7, 10];
    if (quality === 'maj7') intervals = [0, 4, 7, 11];
    if (quality === 'dim') intervals = [0, 3, 6];
    if (quality === 'm7b5') intervals = [0, 3, 6, 10];

    return intervals.map(i => ALL_NOTES[(rootIdx + i) % 12]);
  };

  useEffect(() => {
    const chords = getDiatonicChords();
    setDiatonicChords(chords);
    
    if (chords.length > 0) {
      const name0 = chords[0]?.triad || keyNote || 'C';
      const name1 = chords[2 % chords.length]?.triad || keyNote || 'C';
      const name2 = chords[4 % chords.length]?.triad || keyNote || 'C';
      const name3 = chords[0]?.triad || keyNote || 'C';

      const defaultProg = [
        { name: name0, notes: getChordNotesLocal(name0, keyNote || 'C') },
        { name: name1, notes: getChordNotesLocal(name1, keyNote || 'C') },
        { name: name2, notes: getChordNotesLocal(name2, keyNote || 'C') },
        { name: name3, notes: getChordNotesLocal(name3, keyNote || 'C') }
      ];
      setProgression(defaultProg);
      stopPlayback();
      setTimeout(() => { executeGeneration(defaultProg); }, 50);
    }
    // eslint-disable-next-line
  }, [keyNote, mode]);

  useEffect(() => {
    chordSynthRef.current = new Tone.PolySynth(Tone.Synth, {
      oscillator: { type: 'triangle' },
      envelope: { attack: 0.1, decay: 0.2, sustain: 0.7, release: 1.5 }
    }).toDestination();
    chordSynthRef.current.volume.value = -14;

    soloSynthRef.current = new Tone.PolySynth(Tone.Synth, {
      oscillator: { type: 'sawtooth' },
      envelope: { attack: 0.02, decay: 0.1, sustain: 0.4, release: 0.8 }
    }).toDestination();
    soloSynthRef.current.volume.value = -6;

    metronomeSynthRef.current = new Tone.MembraneSynth({
      pitchDecay: 0.05,
      octaves: 4,
      oscillator: { type: 'sine' },
      envelope: { attack: 0.001, decay: 0.1, sustain: 0, release: 0.1 }
    }).toDestination();
    metronomeSynthRef.current.volume.value = -8;

    const guitarSampler = new Tone.Sampler({
      urls: { "E2": "E2.mp3", "A2": "A2.mp3", "D3": "D3.mp3", "G3": "G3.mp3", "B3": "B3.mp3", "E4": "E4.mp3" },
      baseUrl: "/samples/guitar/",
    }).toDestination();
    samplerRef.current = guitarSampler;

    return () => {
      stopPlayback();
      chordSynthRef.current?.dispose();
      soloSynthRef.current?.dispose();
      metronomeSynthRef.current?.dispose();
      guitarSampler.dispose();
    };
  }, []);

  const playMetronomeClick = (time: number, isAccent: boolean) => {
    if (!isMetronomeOn || !metronomeSynthRef.current) return;
    metronomeSynthRef.current.triggerAttackRelease(isAccent ? "C4" : "C3", "32n", time, isAccent ? 1 : 0.5);
  };

  const startMetronome = () => {
    if (metronomeIntervalRef.current) clearInterval(metronomeIntervalRef.current);
    const currentBpm = bpm || 120;
    const intervalMs = (60 / currentBpm) * 1000;
    let beatCount = 0;
    const beatsPerBar = timeSignature.beats;

    playMetronomeClick(Tone.now(), true);

    metronomeIntervalRef.current = setInterval(() => {
      if (!isPlaying) {
        if (metronomeIntervalRef.current) clearInterval(metronomeIntervalRef.current);
        return;
      }
      beatCount = (beatCount + 1) % 32;
      const isAccent = beatCount % beatsPerBar === 0;
      playMetronomeClick(Tone.now(), isAccent);
    }, intervalMs);
  };

  const stopPlayback = () => {
    scheduledEventsRef.current.forEach(event => { try { event.cancel(); } catch (err) {} });
    scheduledEventsRef.current = [];

    Tone.Transport.stop();
    Tone.Transport.cancel();

    if (loopIntervalRef.current) clearInterval(loopIntervalRef.current);
    if (metronomeIntervalRef.current) clearInterval(metronomeIntervalRef.current);

    chordSynthRef.current?.releaseAll();
    soloSynthRef.current?.releaseAll();
    samplerRef.current?.releaseAll();

    setIsPlaying(false);
    setPlaybackProgress(0);
    cancelAnimationFrame(playheadAnimRef.current);
  };

  const executeGeneration = (targetProgression: { name: string; notes: string[] }[]) => {
    setIsGenerating(true);
    setSoloData(null);
    setPlaybackProgress(0);
    setTips([]);

    const scale = getScaleNotes();
    const safeScale = scale && scale.length > 0 ? scale : ['C', 'D', 'E', 'G', 'A'];

    const newSolo = generateSynchronizedSolo(
      safeScale,
      keyNote || 'C',
      mode || 'major',
      timeSignature || { beats: 4, noteValue: 4 },
      targetProgression,
      false
    );

    setSoloData(newSolo);
    try {
      const chordNames = newSolo.chords.map(c => c.name);
      setTips(generateTips(newSolo as any, keyNote || 'C', mode || 'major', chordNames, bpm || 120));
    } catch (err) {}
    setIsGenerating(false);
  };

  const handleGenerateClick = (e: React.MouseEvent) => {
    (e.currentTarget as HTMLButtonElement).blur();
    if (isPlaying) stopPlayback();
    executeGeneration(progression);
  };

  const togglePlay = async (e?: React.MouseEvent) => {
    if (e) (e.currentTarget as HTMLButtonElement).blur();
    if (!soloData) return;
    if (isPlaying) { stopPlayback(); return; }

    await Tone.start();
    setIsPlaying(true);
    
    const currentBpm = bpm || 120;
    Tone.Transport.bpm.value = currentBpm;
    const quarterDuration = 60 / currentBpm;
    const totalDurationSec = soloData.totalBeats * quarterDuration;

    if (isMetronomeOn) startMetronome();

    const startPlayback = (startTime: number) => {
      scheduledEventsRef.current.forEach(ev => { try { ev.cancel(); } catch(err){} });
      scheduledEventsRef.current = [];

      if (isChordsOn) {
        soloData.chords.forEach(chord => {
          const time = startTime + chord.beatStart * quarterDuration;
          const duration = chord.durationBeats * quarterDuration;
          const freqs = (chord.notes && chord.notes.length > 0 ? chord.notes : [keyNote]).map(n => `${n.replace(/[0-9]/g, '')}3`);
          chordSynthRef.current?.triggerAttackRelease(freqs, duration * 0.95, time);
        });
      }

      if (isSoloOn) {
        const OPEN_FREQS = [329.63, 246.94, 196.00, 146.83, 110.00, 82.41];
        const activeInst = samplerRef.current?.loaded ? samplerRef.current : soloSynthRef.current;
        
        soloData.notes.forEach(note => {
          if (!note.isRest && note.fret !== null) {
            const time = startTime + note.beatStart * quarterDuration;
            const duration = note.beatDuration * quarterDuration * (note.durationFactor || 1);
            const freq = OPEN_FREQS[note.string] * Math.pow(2, note.fret / 12);
            activeInst?.triggerAttackRelease(freq, duration, time, note.accent ? 0.9 : 0.6);
          }
        });
      }
    };

    const startTime = Tone.now() + 0.05;
    startPlayback(startTime);

    if (isLoopOn) {
      loopIntervalRef.current = setInterval(() => {
        if (!isPlaying) { clearInterval(loopIntervalRef.current); return; }
        startPlayback(Tone.now() + 0.05);
      }, totalDurationSec * 1000);
    }

    const drawPlayhead = () => {
      const now = Tone.now();
      let progress = (now - startTime) / totalDurationSec;
      if (isLoopOn) progress = Math.max(0, progress % 1);
      
      if (progress >= 1 && !isLoopOn) {
        setPlaybackProgress(1);
        stopPlayback();
        setTimeout(() => setPlaybackProgress(0), 400);
      } else {
        setPlaybackProgress(progress);
        playheadAnimRef.current = requestAnimationFrame(drawPlayhead);
      }
    };
    playheadAnimRef.current = requestAnimationFrame(drawPlayhead);
  };

  const SVG_WIDTH = 1200;
  const SVG_HEIGHT = 440;
  const TRACK_MARGIN_X = 20;
  const BAR_WIDTH = (SVG_WIDTH - TRACK_MARGIN_X * 2) / 4;
  const BEAT_WIDTH = BAR_WIDTH / (timeSignature?.beats || 4);
  const CHORD_Y = 35;
  const TAB_Y = 120;

  return (
    <div style={{ width: '100%', display: 'flex', flexDirection: 'column', gap: '20px', padding: '12px 0' }}>
      
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '16px', width: '100%' }}>
        <div>
          <h2 style={{ margin: '0 0 6px 0', fontSize: '18px', fontWeight: 900, color: 'var(--text-primary)' }}>🎼 AI Studio Progress Composer</h2>
          <div style={{ display: 'flex', gap: '12px', fontSize: '12px', color: 'var(--text-muted)' }}>
            <span>Тональность: <strong style={{ color: 'var(--accent)' }}>{keyNote} {mode.replace(/_/g, ' ')}</strong></span>
            <span>Размер: <strong>{timeSignature.beats}/{timeSignature.noteValue}</strong></span>
          </div>
        </div>

        <div style={{ display: 'flex', gap: '12px', alignItems: 'center' }}>
          <select value={keyNote} onChange={e => setKeyNote(e.target.value)} style={{ background: '#111216', color: '#fff', border: '1px solid var(--border-color)', padding: '6px 12px', borderRadius: '6px', fontWeight: 700 }}>
            {ALL_NOTES.map(n => <option key={n} value={n}>{n}</option>)}
          </select>
          
          <select value={mode} onChange={e => setMode(e.target.value as any)} style={{ background: '#111216', color: '#fff', border: '1px solid var(--border-color)', padding: '6px 12px', borderRadius: '6px', fontWeight: 700, textTransform: 'capitalize' }}>
            <option value="major">Major (Ionian)</option>
            <option value="minor">Minor (Aeolian)</option>
            <option value="harmonic_minor">Harmonic Minor</option>
            <option value="melodic_minor">Melodic Minor</option>
            <option value="pentatonic">Pentatonic</option>
            <option value="blues">Blues</option>
            <option value="dorian">Dorian</option>
            <option value="phrygian">Phrygian</option>
            <option value="lydian">Lydian</option>
            <option value="mixolydian">Mixolydian</option>
            <option value="locrian">Locrian</option>
            <option value="maj7_arp">Maj7 Arpeggio</option>
            <option value="min7_arp">Min7 Arpeggio</option>
            <option value="dom7_arp">Dom7 Arpeggio</option>
            <option value="dom9_arp">Dom9 Arpeggio</option>
            <option value="altered">Altered</option>
          </select>

          <div style={{ display: 'flex', gap: '6px' }}>
            {!isPlaying ? (
              <button onClick={togglePlay} disabled={!soloData || isGenerating} style={{ background: 'var(--accent)', color: '#000', border: 'none', padding: '8px 18px', borderRadius: '6px', fontWeight: 900, cursor: 'pointer' }}>▶ PLAY</button>
            ) : (
              <button onClick={(e) => { (e.currentTarget as HTMLButtonElement).blur(); stopPlayback(); }} style={{ background: '#ff4444', color: '#fff', border: 'none', padding: '8px 18px', borderRadius: '6px', fontWeight: 900, cursor: 'pointer' }}>⏹ STOP</button>
            )}
            
            <button 
              onClick={(e) => { (e.currentTarget as HTMLButtonElement).blur(); setIsLoopOn(!isLoopOn); }} 
              style={{ background: isLoopOn ? 'var(--accent)' : 'transparent', color: isLoopOn ? '#000' : 'var(--text-muted)', border: '1px solid var(--border-color)', padding: '6px 12px', borderRadius: '6px', fontWeight: 800, cursor: 'pointer' }}
            >
              🔁 LOOP: {isLoopOn ? 'ON' : 'OFF'}
            </button>
          </div>

          <button onClick={handleGenerateClick} disabled={isGenerating || isPlaying} style={{ background: 'var(--bg-primary)', color: 'var(--text-primary)', border: '1px solid var(--border-color)', padding: '8px 20px', borderRadius: '6px', fontWeight: 800, cursor: 'pointer' }}>
            {isGenerating ? '⏳ RENDERING...' : '🎲 GENERATE'}
          </button>
        </div>
      </div>

      <div style={{ display: 'flex', gap: '16px', alignItems: 'center', background: 'var(--bg-root)', padding: '10px 16px', borderRadius: '8px', flexWrap: 'wrap', width: '100%' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
          <span style={{ fontSize: '11px', color: 'var(--text-muted)', fontWeight: 800 }}>TEMPO</span>
          <input type="number" value={bpm} onChange={e => setBpm(Number(e.target.value))} style={{ width: '60px', background: 'var(--bg-secondary)', border: '1px solid var(--border-color)', borderRadius: '4px', color: '#fff', textAlign: 'center', fontWeight: 900 }} />
        </div>
        <button onClick={(e) => { (e.currentTarget as HTMLButtonElement).blur(); setIsMetronomeOn(!isMetronomeOn); }} style={{ background: isMetronomeOn ? 'var(--accent)' : 'transparent', color: isMetronomeOn ? '#000' : 'var(--text-muted)', border: '1px solid var(--border-color)', padding: '4px 12px', borderRadius: '4px', fontSize: '12px', fontWeight: 700 }}>
          Metronome: {isMetronomeOn ? 'ON' : 'OFF'}
        </button>
        <label style={{ display: 'flex', alignItems: 'center', gap: '6px', color: 'var(--text-primary)', fontSize: '13px', fontWeight: 700, cursor: 'pointer' }}>
          <input type="checkbox" checked={isChordsOn} onChange={e => setIsChordsOn(e.target.checked)} /> Chords Backing
        </label>
        <label style={{ display: 'flex', alignItems: 'center', gap: '6px', color: 'var(--text-primary)', fontSize: '13px', fontWeight: 700, cursor: 'pointer' }}>
          <input type="checkbox" checked={isSoloOn} onChange={e => setIsSoloOn(e.target.checked)} /> Lead Solo
        </label>
      </div>

      <div style={{ width: '100%', background: '#090a0e', borderRadius: '12px', border: '1px solid var(--border-color)', overflowX: 'auto', position: 'relative', minHeight: `${SVG_HEIGHT}px` }}>
        {soloData ? (
          <>
            <svg width={SVG_WIDTH} height={SVG_HEIGHT} style={{ display: 'block', minWidth: '100%' }}>
              {Array.from({ length: 4 }).map((_, barIdx) => {
                const x = TRACK_MARGIN_X + barIdx * BAR_WIDTH;
                return (
                  <g key={barIdx}>
                    <line x1={x} y1={0} x2={x} y2={SVG_HEIGHT} stroke="rgba(255,255,255,0.15)" strokeWidth="1.5" />
                    <text x={x + BAR_WIDTH / 2} y={21} fill="var(--text-muted)" fontSize="11" fontWeight="900" textAnchor="middle">
                      Bar {barIdx + 1}
                    </text>
                    {/* Пунктирные линии для слабых долей */}
                    {Array.from({ length: timeSignature?.beats || 4 }).map((__, beatIdx) => {
                      if (beatIdx === 0) return null;
                      const beatX = x + beatIdx * BEAT_WIDTH;
                      return <line key={`beat-${barIdx}-${beatIdx}`} x1={beatX} y1={CHORD_Y} x2={beatX} y2={SVG_HEIGHT} stroke="rgba(255,255,255,0.05)" strokeWidth="1" strokeDasharray="4 4" />;
                    })}
                  </g>
                );
              })}
              <line x1={SVG_WIDTH - TRACK_MARGIN_X} y1={0} x2={SVG_WIDTH - TRACK_MARGIN_X} y2={SVG_HEIGHT} stroke="rgba(255,255,255,0.15)" strokeWidth="1.5" />

              {progression.map((chord, idx) => {
                const x = TRACK_MARGIN_X + idx * BAR_WIDTH;
                return (
                  <g key={idx}>
                    <rect 
                      x={x + 6} y={CHORD_Y} 
                      width={BAR_WIDTH - 12} height="36" 
                      fill="rgba(0,255,157,0.04)" 
                      stroke={editingBarIndex === idx ? "var(--accent)" : "rgba(0,255,157,0.15)"} 
                      strokeWidth={editingBarIndex === idx ? 2 : 1}
                      rx="6" 
                      style={{ cursor: 'pointer' }}
                      onClick={(e) => { e.stopPropagation(); setEditingBarIndex(editingBarIndex === idx ? null : idx); }}
                    />
                    <text 
                      x={x + BAR_WIDTH / 2} y={CHORD_Y + 23} 
                      fill="var(--accent)" 
                      fontSize="15" fontWeight="900" textAnchor="middle" 
                      style={{ cursor: 'pointer' }}
                      onClick={(e) => { e.stopPropagation(); setEditingBarIndex(editingBarIndex === idx ? null : idx); }}
                    >
                      {chord.name} ▾
                    </text>
                  </g>
                );
              })}

              <foreignObject x={TRACK_MARGIN_X} y={TAB_Y} width={SVG_WIDTH - TRACK_MARGIN_X * 2} height={280}>
                <div style={{ width: '100%', height: '100%', overflow: 'hidden' }}>
                  <TablatureDisplay 
                    notes={soloData.notes} 
                    activeStep={isPlaying && isSoloOn ? Math.floor(playbackProgress * soloData.notes.length) : -1} 
                    height={260} 
                    noteSpacing={85} 
                  />
                </div>
              </foreignObject>

              {isPlaying && (
                <line x1={TRACK_MARGIN_X + playbackProgress * (SVG_WIDTH - TRACK_MARGIN_X * 2)} y1={CHORD_Y} x2={TRACK_MARGIN_X + playbackProgress * (SVG_WIDTH - TRACK_MARGIN_X * 2)} y2={SVG_HEIGHT} stroke="var(--accent)" strokeWidth="2.5" style={{ filter: 'drop-shadow(0 0 6px var(--accent))' }} />
              )}
            </svg>

            {editingBarIndex !== null && (
              <div style={{ position: 'absolute', top: `${CHORD_Y + 42}px`, left: `${TRACK_MARGIN_X + editingBarIndex * BAR_WIDTH + 6}px`, width: `${BAR_WIDTH - 12}px`, background: 'var(--bg-panel)', border: '1px solid var(--border-color)', borderRadius: '6px', zIndex: 999, overflow: 'hidden', boxShadow: '0 8px 24px rgba(0,0,0,0.6)' }}>
                {diatonicChords.map((opt, oIdx) => {
                  const name = opt.triad || opt.seventhChord || keyNote;
                  return (
                    <div 
                      key={oIdx} 
                      onClick={() => {
                        const nextProg = [...progression];
                        nextProg[editingBarIndex] = { name, notes: getChordNotesLocal(name, keyNote || 'C') };
                        setProgression(nextProg);
                        setEditingBarIndex(null);
                        setTimeout(() => executeGeneration(nextProg), 40);
                      }}
                      style={{ padding: '8px 12px', cursor: 'pointer', fontSize: '13px', fontWeight: 800, borderBottom: '1px solid rgba(255,255,255,0.03)', color: 'var(--text-primary)' }}
                      onMouseEnter={e => { e.currentTarget.style.background = 'var(--accent)'; e.currentTarget.style.color = '#000'; }}
                      onMouseLeave={e => { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.color = 'var(--text-primary)'; }}
                    >
                      {opt.baseRoman} ({name})
                    </div>
                  );
                })}
              </div>
            )}
          </>
        ) : (
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '320px', color: 'var(--text-muted)', fontWeight: 800, fontSize: '13px' }}>
            {isGenerating ? 'ВЫЧИСЛЕНИЕ ПРОГРЕССИИ И ГЕНЕРАЦИЯ ФРАЗ...' : 'СЕТКА ПУСТА. НАЖМИТЕ GENERATE ДЛЯ СОЗДАНИЯ 4-ТАКТНОГО СОЛО'}
          </div>
        )}
      </div>

      {tips.length > 0 && (
        <div style={{ borderTop: '1px solid var(--border-color)', paddingTop: '16px', display: 'flex', flexDirection: 'column', gap: '8px', width: '100%' }}>
          <span style={{ fontSize: '11px', color: 'var(--text-muted)', fontWeight: 800, textTransform: 'uppercase' }}>💡 Аналитический разбор ИИ:</span>
          {tips.map((tip, i) => (
            <div key={i} style={{ fontSize: '12px', background: 'rgba(0,255,157,0.04)', padding: '10px 14px', borderRadius: '6px', borderLeft: '3px solid var(--accent)', color: 'var(--text-primary)' }}>
              <strong>{tip.title}:</strong> {tip.description}
            </div>
          ))}
        </div>
      )}

    </div>
  );
};

export default SoloGenerator;